import{_ as l,o as a,c as e,a2 as r}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"Lili 深度学习文章标准","description":"","frontmatter":{},"headers":[],"relativePath":"skills/write-lili-learning-notes/references/article-standard.md","filePath":"skills/write-lili-learning-notes/references/article-standard.md","lastUpdated":1784250624000}'),t={name:"skills/write-lili-learning-notes/references/article-standard.md"};function o(n,i,d,h,s,c){return a(),e("div",null,[...i[0]||(i[0]=[r('<h1 id="lili-深度学习文章标准" tabindex="-1">Lili 深度学习文章标准 <a class="header-anchor" href="#lili-深度学习文章标准" aria-label="Permalink to &quot;Lili 深度学习文章标准&quot;">​</a></h1><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><ol><li>正文原则</li><li>入门与初级模板</li><li>中级模板</li><li>概念展开规则</li><li>示例规则</li><li>事实与时效审计</li><li>正文禁区</li><li>完成检查</li></ol><h2 id="_1-正文原则" tabindex="-1">1. 正文原则 <a class="header-anchor" href="#_1-正文原则" aria-label="Permalink to &quot;1. 正文原则&quot;">​</a></h2><p>文章必须让没有外部上下文的读者完成一次独立学习。正文直接讲知识，不讲作者如何搜索、参考了谁的写法、为什么修改文章或资料何时更新。</p><p>每篇围绕一个明确知识点回答：</p><ul><li>是什么：严格定义、输入输出、组成和相邻概念。</li><li>为什么：它解决的真实问题、缺失时会发生什么。</li><li>怎样工作：机制、流程、状态、因果和约束。</li><li>怎样使用：步骤、代码、命令、模板、计算或设计操作。</li><li>有什么特殊行为：默认值、继承、优先级、兼容性、生命周期和例外。</li><li>怎样失败：常见误用、边界、反例、安全与生产风险。</li><li>怎样验证：观察点、测试、调试工具、指标和完成标准。</li></ul><h2 id="_2-入门与初级模板" tabindex="-1">2. 入门与初级模板 <a class="header-anchor" href="#_2-入门与初级模板" aria-label="Permalink to &quot;2. 入门与初级模板&quot;">​</a></h2><p>按主题调整标题，但必须覆盖以下内容：</p><ol><li>标题和一句准确定位。</li><li>概念定义及最小前置知识。</li><li>工作机制或结构图。</li><li>组成部分逐项解释。</li><li>最小完整示例。</li><li>属性、参数、方法、状态或类型明细。</li><li>至少一个可运行、可计算或可执行的应用示例。</li><li>示例结果、渲染结果或可观察状态。</li><li>常见错误、边界和修正方法。</li><li>调试或验证步骤。</li><li>练习与明确完成标准。</li><li><code>## 来源</code>，列出 2–5 个直接可靠来源及访问日期。</li></ol><p>不要为了模板强行重复。如果“组成部分”和“属性明细”是同一内容，应合并为一张有解释的表格。</p><p>扩写旧文章时必须重构成一条连续的教学路径。旧版“是什么/为什么/怎么用/反例/练习”等摘要内容应合并到深化后的对应章节，不能保留整套短模板后，再在文末追加第二套概念解释、完整案例和检查表。读者不应先读一遍摘要，再读一遍同义扩展。</p><h2 id="_3-中级模板" tabindex="-1">3. 中级模板 <a class="header-anchor" href="#_3-中级模板" aria-label="Permalink to &quot;3. 中级模板&quot;">​</a></h2><p>中级文章假定读者已掌握前置概念，必须增加应用深度：</p><ol><li>能力边界和前置知识链接。</li><li>底层机制、关键数据流或决策过程。</li><li>至少两个不同约束下的完整应用案例。</li><li>方案 A/B/C 的适用条件、成本和取舍。</li><li>可运行代码、完整分析、交互状态表、SQL、命令或配置。</li><li>调试路径、观测信号和验证方法。</li><li>性能、安全、无障碍、数据、成本或运维边界中与主题有关的部分。</li><li>失败注入、异常场景或反例。</li><li>与其他模块的集成方式。</li><li>综合练习或小项目及验收标准。</li><li>2–5 个一手来源及访问日期。</li></ol><h2 id="_4-概念展开规则" tabindex="-1">4. 概念展开规则 <a class="header-anchor" href="#_4-概念展开规则" aria-label="Permalink to &quot;4. 概念展开规则&quot;">​</a></h2><p>出现以下内容时逐项解释，不只罗列名称：</p><ul><li>属性：作用、值域、缺失值、无效值、适用元素、继承/反射、特殊行为和示例。</li><li>函数或方法：签名、参数、返回值、异常、副作用、时序和示例。</li><li>配置项：默认值、合法值、覆盖顺序、环境差异和安全影响。</li><li>状态：进入条件、退出条件、允许转移、持久化和恢复。</li><li>指标：定义、单位、采样点、聚合方法、误读方式和决策用途。</li><li>算法：输入、输出、不变量、复杂度、适用数据和失败边界。</li><li>产品或设计框架：它是组织假设的方法，不是自然定律；说明输入证据、判断步骤和不可用场景。</li><li>标准或规范：区分规范要求、浏览器/平台实现、兼容性和项目约定。</li></ul><p>篇幅由知识点决定，不用重复文字凑长度。对本路线的入门/初级文章，低于约 120 行或 8 KB 通常意味着只有摘要，必须重新检查是否遗漏机制、逐项说明、完整案例、可观察结果、错误修正和练习；中级文章低于约 200 行或 12 KB 通常不足以承载两个实质案例、方案取舍、调试和生产边界。达到长度不是完成条件，一个名称不能代替解释，一张大而空的清单不能代替教程。</p><p>完整案例不得只有一两句话。至少包含具体输入或证据、逐步处理过程、产生的输出、验证方法和一个失败分支。产品与交互主题也必须展示实际推理和决策过程，不能在固定的“证据输入/反例/验证步骤”标题下各写一行后宣告完成。</p><h2 id="_5-示例规则" tabindex="-1">5. 示例规则 <a class="header-anchor" href="#_5-示例规则" aria-label="Permalink to &quot;5. 示例规则&quot;">​</a></h2><ul><li>示例先小后完整，变量和业务语义保持一致。</li><li>代码不得使用不存在的 API、无效占位语法或危险生产命令。</li><li>省略代码时明确标注省略范围，不把伪代码放进具体语言围栏。</li><li>命令说明运行环境、前置条件和副作用。</li><li>SQL 说明事务、锁、索引、数据量或回滚风险。</li><li>产品示例给出输入证据、决策过程和输出，而不是只填一张空模板。</li><li>交互示例覆盖加载、空、错误、成功、权限、键盘和恢复等相关状态。</li><li>AI 示例记录模型/API类别、结构校验、失败状态、费用/Token或评估边界；不承诺模型确定正确。</li><li>渲染图片必须来自仓库中的可运行示例。图片格式与扩展名一致，正文使用相对路径。</li><li>仓库内部链接统一使用相对 Markdown 链接，不使用 GitHub 无法解析的 Obsidian Wiki Link。</li><li>完整 HTML 示例必须通过 Nu HTML Checker 或等价 HTML5 校验；JavaScript、TypeScript、Go、SQL、Shell 与配置示例使用对应解析器、编译器、测试或安全的 dry-run 验证。</li></ul><h2 id="_6-事实与时效审计" tabindex="-1">6. 事实与时效审计 <a class="header-anchor" href="#_6-事实与时效审计" aria-label="Permalink to &quot;6. 事实与时效审计&quot;">​</a></h2><p>对每个知识点从第一性问题开始：</p><ol><li>该词准确指什么对象？</li><li>规则由哪个规范、实现、产品或团队定义？</li><li>结论成立需要哪些前提？</li><li>是否存在默认值、例外、兼容性或版本差异？</li><li>示例能否真实复现结论？</li><li>来源是否直接支撑正文，而非只与主题相关？</li></ol><p>优先级：Living Standard/正式规范/官方文档 → 原始论文/源码/官方数据 → 高质量二手资料。对快速变化的 API、浏览器能力、法律、产品接口、模型和框架必须联网复核。</p><p>正文只保留读者需要的实际状态。例如写“<code>hidden</code> 是具有 Hidden 与 Hidden Until Found 状态的枚举属性”，不要写“核对资料后发现旧教程把它写错了”。</p><h2 id="_7-正文禁区" tabindex="-1">7. 正文禁区 <a class="header-anchor" href="#_7-正文禁区" aria-label="Permalink to &quot;7. 正文禁区&quot;">​</a></h2><p>删除以下类型文字：</p><ul><li>“本文参考了……的写作方式”。</li><li>“经过联网搜索/核对后发现……”。</li><li>“这个列表以后还会变化，请以官网为准”。</li><li>“为了完整性，我们在这里加入……”。</li><li>“前面已经说过”“不难理解”“显而易见”“只要记住”。</li><li>对读者没有操作价值的更新时间、生成过程、任务分工和维护说明。</li><li>比喻、鸡汤、重复结论和凑篇幅的小结。</li></ul><p>版本、日期或兼容性若会改变读者决策，应直接写入具体条目，例如“该属性目前不是 Baseline，需要特性检测”，而不是写编辑说明。</p><h2 id="_8-完成检查" tabindex="-1">8. 完成检查 <a class="header-anchor" href="#_8-完成检查" aria-label="Permalink to &quot;8. 完成检查&quot;">​</a></h2><ul><li>[ ] 标题与 roadmap 知识点一致。</li><li>[ ] 所有关键名词均有定义和实际作用。</li><li>[ ] 每个属性/参数/状态有行为与边界，不是名称清单。</li><li>[ ] 至少一个完整示例可执行或可验证。</li><li>[ ] 中级文章至少两个实质应用案例。</li><li>[ ] 图表确实降低理解成本。</li><li>[ ] UI/网页示例已真实渲染并检查交互和错误日志。</li><li>[ ] 事实、兼容性和弃用状态已联网核对。</li><li>[ ] 没有编辑过程或写作参考说明。</li><li>[ ] 没有“旧摘要 + 后置扩展”的双重教学路径或重复案例。</li><li>[ ] 来源直接、可访问且数量适当。</li><li>[ ] Markdown 链接、图片、代码围栏和相对路径有效。</li><li>[ ] 不存在 <code>[[Wiki Link]]</code>，GitHub、Obsidian、VS Code 均可导航。</li><li>[ ] 完整可运行示例已通过适用的语法或行为验证。</li><li>[ ] <code>git diff --check</code> 通过。</li></ul>',33)])])}const _=l(t,[["render",o]]);export{u as __pageData,_ as default};
